P CreateFail      B
D CreateFail      PI
D   Failure                      2  0 value
D   Groups                       4A   value
D   PartNo                       7A   value
D   Maintenance                  1N   value
D   Text                        65A   Dim(4) value
D   valueMat                    11  2 value
D   valueLab                    11  2 value
D   valueSpe                    11  2 value
D*----------------------------------------------------------------
D*****************************************************************
 /free
   Clear HSG73PR;
   G73000 = G71000;
   G73010 = G71010;
   G73020 = G71020;
   G73030 = G71030;
   G73040 = G71040;
   G73050 = G71050;
   G73060 = %EditC(Failure:'X');
   If partNo = *Blanks;
      G73070 = G79_SVT;
   Else;
      G73070 = partNo;
   EndIf;
   If %Subst(Groups:1:2) = *Blanks;
      G73080 = '00';
   Else;
      G73080 = %Subst(Groups:1:2);
   EndIf;
   If %Subst(Groups:3:2) = *Blanks;
      G73090 = '00';
   Else;
      G73090 = %Subst(Groups:3:2);
   EndIf;
   G73100 = G79_SC;
   G73120 = Text(1);
   G73130 = Text(2);
   G73140 = G79_DC;
   If Maintenance;
      %Subst(G73140:1:1) = 'W';
   EndIf;
   If BTS060 = 'SAT' And %Subst(G73140:2:1) = '2';
      %Subst(G73140:2:1) = '8';
   EndIf;
   Chain G73140 S3f085;
   If %Found(S3f085);
      G73180 = DMCPWF;
      G73190 = DLCPWF;
      G73200 = DSCPWF;
   EndIf;
   G73210 = valueMat;
   G73220 = valueLab;
   G73230 = valueSpe;
   G73240 = 1;
   G73290 = 0;
   G73320 = Text(3);
   G73330 = Text(4);
   G73340 = G73060;
   //Freigabe-Nr. ermitteln
   If %SUBST(GetScope(G73140):1:1) = 'R';
      SetLl (G71000:G71030 + G71040) RWAPRL1;
      ReadE (G71000:G71030 + G71040) RWAPRL1;
      DoW Not %Eof(RWAPRL1);
         If APR_NR <> *Blanks And G71060 = APR_FGNR;
            %SUBST(G73330:47:14) = APR_NR;
         EndIf;
         ReadE (G71000:G71030 + G71040) RWAPRL1;
      EndDo;
   EndIf;
   Write(E) HSG73PR;
   Auto = 'J';
   CallHS1217(G71000:G71010:G71020:G71030:G71040:G71050:G73060:
              Aktion:Auto);
   Return;
 /end-free
P                 E

